import type { ParsedMessage } from '@/shared/types'
import { BaseAdapter } from './base'

// TODO: Verify selectors against current tongyi.aliyun.com DOM
const USER_SEL  = '.chat-message--human'
const MODEL_SEL = '.chat-message--assistant'

export class TongyiAdapter extends BaseAdapter {
  readonly platform = 'tongyi' as const

  detectPlatform(): boolean {
    return location.hostname.includes('tongyi.aliyun.com')
  }

  extractConvId(url: string): string | null {
    const match = url.match(/sessionId=([^&]+)/)
    return match?.[1] ?? null
  }

  parseMessages(): ParsedMessage[] {
    const results: ParsedMessage[] = []
    const allTurns = document.querySelectorAll<HTMLElement>(
      `${USER_SEL}, ${MODEL_SEL}`
    )
    allTurns.forEach((el, i) => {
      const role = el.matches(USER_SEL) ? 'user' as const : 'assistant' as const
      const content = el.textContent?.trim() ?? ''
      if (!content) return
      results.push({ platformId: `tongyi-turn-${i}`, role, content })
    })
    return results
  }
}
